const fs = require('fs');
const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType,
  LevelFormat
} = require('docx');

// Helper: heading
function h1(text) {
  return new Paragraph({ heading: HeadingLevel.HEADING_1, spacing: { before: 400, after: 200 }, children: [new TextRun({ text, bold: true, font: 'Arial', size: 32 })] });
}
function h2(text) {
  return new Paragraph({ heading: HeadingLevel.HEADING_2, spacing: { before: 300, after: 150 }, children: [new TextRun({ text, bold: true, font: 'Arial', size: 28 })] });
}
function h3(text) {
  return new Paragraph({ heading: HeadingLevel.HEADING_3, spacing: { before: 200, after: 100 }, children: [new TextRun({ text, bold: true, font: 'Arial', size: 24 })] });
}

// Helper: paragraph
function p(text, opts = {}) {
  return new Paragraph({
    spacing: { after: 120 },
    children: [new TextRun({ text, font: 'Arial', size: 22, ...opts })]
  });
}

// Helper: bold paragraph
function pb(text) {
  return p(text, { bold: true });
}

// Helper: italic paragraph
function pi(text) {
  return p(text, { italics: true });
}

// Helper: label (small caps style)
function label(text) {
  return new Paragraph({
    spacing: { before: 100, after: 80 },
    children: [new TextRun({ text, font: 'Arial', size: 20, bold: true, color: '888888' })]
  });
}

// Helper: mixed bold+normal in one paragraph
function pmix(parts) {
  return new Paragraph({
    spacing: { after: 120 },
    children: parts.map(([text, opts]) => new TextRun({ text, font: 'Arial', size: 22, ...opts }))
  });
}

// Helper: field label + value
function field(lbl, val) {
  return pmix([[lbl + ' ', { bold: true }], [val, {}]]);
}

// Helper: separator
function sep() {
  return new Paragraph({ spacing: { before: 200, after: 200 }, children: [new TextRun({ text: '\u2500'.repeat(50), font: 'Arial', size: 18, color: 'CCCCCC' })] });
}

// Helper: numbered card
function card(num, text) {
  return pmix([[num + ' \u2014 ', { bold: true }], [text, {}]]);
}

// Simple table
const border = { style: BorderStyle.SINGLE, size: 1, color: 'CCCCCC' };
const borders = { top: border, bottom: border, left: border, right: border };
const margins = { top: 60, bottom: 60, left: 100, right: 100 };

function makeTable(headers, rows) {
  const colCount = headers.length;
  const colWidth = Math.floor(9360 / colCount);
  const colWidths = headers.map(() => colWidth);

  const headerRow = new TableRow({
    children: headers.map(h => new TableCell({
      borders,
      width: { size: colWidth, type: WidthType.DXA },
      shading: { fill: 'F0ECE4', type: ShadingType.CLEAR },
      margins,
      children: [new Paragraph({ children: [new TextRun({ text: h, bold: true, font: 'Arial', size: 20 })] })]
    }))
  });

  const dataRows = rows.map(cells =>
    new TableRow({
      children: cells.map(c => new TableCell({
        borders,
        width: { size: colWidth, type: WidthType.DXA },
        margins,
        children: [new Paragraph({ children: [new TextRun({ text: c, font: 'Arial', size: 20 })] })]
      }))
    })
  );

  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: colWidths,
    rows: [headerRow, ...dataRows]
  });
}

